var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"끝났어!","JPN":"できた！","ENG":"It's done!","TWN":"好了！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"문제를 일으킨 기판을 교체했으니, 이제 작동할 거야!","JPN":"問題のある基板を交替したから、もう動くはずだよ！","ENG":"I've replaced all the faulty circuit boards, so it should work now!","TWN":"更換了出問題的線路板，現在應該能運作了！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"7번과 8번 수정의 오류 정화 확인…! 정상적으로 작동합니다!","JPN":"7番と8番水晶のエラー浄化を確認……！　正常に作動しています！","ENG":"Crystals no. 7 and 8's error correction confirmed...! Operating as normal!","TWN":"確認修正了7號和8號水晶的錯誤…！正常運作了！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"다른 보조장치들도 이상 없습니다!","JPN":"他の補助装置も異常ありません！","ENG":"The auxiliary devices are also good!","TWN":"其他輔助裝置也沒有問題！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"중앙 동력 가동. 고정 좌표로 도약 관문 활성화.","JPN":"中央動力稼働。固定座標で跳躍関門を活性化。","ENG":"Central power in operation. Activating space jump gateway with the fixed coordinates.","TWN":"啟動中央動力，啟動固定座標的躍遷門。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"도약 관문 활성화…!","JPN":"跳躍関門を活性化……！","ENG":"Gateway activated...!","TWN":"躍遷門啟動…！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"관문의 가시파장에 낙원의 풍경이 잡힙니다…! 연결이 성공했어요…!","JPN":"関門の可視波長に楽園の姿を捉えました……！　連結成功です……！","ENG":"The visible wavelengths are displaying the Promised Land's scenery...! The link was a success...!","TWN":"門的可見波長捕捉到了樂園的景象…！連接成功了…！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원이다!","JPN":"楽園だ！","ENG":"It's the Promised Land!","TWN":"是樂園！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"됐어! 성공했다고!","JPN":"やった！　成功したぞ！","ENG":"We did it! Success!","TWN":"好了！成功了！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아직 기뻐하긴 일러.","JPN":"まだ喜ぶには早いわ。","ENG":"It is too early to celebrate.","TWN":"現在高興還太早。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기의 모두를 전송시키는 게 원래 목적이었지만, 우리가 가진 적철이 그만큼 여유롭진 않아.","JPN":"切り株のみんなを伝送させるのが最初の目的だったけど、アタシの持つ赤鉄だけじゃ足りない。","ENG":"Our original plan was to migrate everyone in the Stump, but we currently do not have enough Violarite.","TWN":"原本的目的是傳送木墩所有的成員，但我們手頭的赤鐵並不充裕。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"…그 말씀이 맞습니다.","JPN":"……おっしゃる通りです。","ENG":"...That is correct.","TWN":"…您說得沒錯。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"지금의 저희 기술력으론… 성인 다섯 명 정도를 전송하는 게 한계로군요.","JPN":"今の私たちの技術力では……大人を5人ほど伝送するのが限界ですね。","ENG":"With our current technology... we will only be able to send about five adults through.","TWN":"以我們現在的技術…最多只能傳送五個成年人。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"고작… 다섯 명…?","JPN":"たったの……5人……？","ENG":"Only... five...?","TWN":"僅僅…五個人…？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"그 오랜 세월 끝에 얻어낸 결과가 이 정도인 건가.","JPN":"この長い研究の果てに得た結果がこれか。","ENG":"After all these years, is this all that we have achieved?","TWN":"經過這麼多年的努力，結果就只有這點嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"효율을 개선하려 노력했지만… 이게 최선이었습니다.","JPN":"改善しようと頑張ったのですが……これが精一杯でした。","ENG":"We tried to improve its efficiency, but... this was the best we could do.","TWN":"雖然努力提高了效率…但這已經是極限了。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"전부 제 역량이 부족한 탓이예요.","JPN":"すべて私の力不足のせいです。","ENG":"It is all because of my lack of capabilities.","TWN":"都是因為我能力不足。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"자책은 미뤄둬. 우리가 종말에 쫓기는 건 그 누구의 책임도 아니야.","JPN":"自分を攻めるのはよしなさい。アタシたちが終末に追われているのは誰のせいでもないわ。","ENG":"Put off blaming yourself for later. It is no one's fault that the end of the world is near.","TWN":"先別自責。我們被末日追趕，這不是任何人的錯。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그리고 인원은 좀 더 늘릴 방법이 있어.","JPN":"それに、送られる人をもう少し増やす方法があるの。","ENG":"Also, there is a way to increase the number of people.","TWN":"而且肯定還有辦法來增加人數。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"도약에 필요한 에너지는 사람의 수가 아닌 질량에 비례하니까.","JPN":"跳躍に必要なエネルギーは人の数ではなく、質量に比例するから。","ENG":"The energy required for the jump depends not on the number of people, but the mass.","TWN":"躍遷所需的能量，是按品質而不是人數來計算的。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"…그렇겠군요.","JPN":"……そうですね。","ENG":"...I see.","TWN":"…原來如此。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"아이들을 데려오겠습니다.","JPN":"子どもたちを連れてきます。","ENG":"I will bring the children.","TWN":"我去帶孩子們過來。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"이봐! 병기마가 돌아온다! 관문을 열어!","JPN":"おい！　兵器馬が戻ってきたぞ！　関門を開けろ！","ENG":"Look! The carriage is back! Open the gates!","TWN":"喂！調查團回來了！快開門！"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};